`, now.Format(time.RFC3339), state.CanonicalPlanDir, state.Workflow.CurrentNodeID, state.ImplementationCwd, path, stateFile, state.SourceCwd, state.ManagerRunID, state.ManagerPaneID, child, stateFile, stateFile)
